'use strict';
// scripts/staging-verify-auth.js
// Verifies that the staging Rust service correctly enforces auth:
//   1. Missing token → 401
//   2. Invalid token → 401
//   3. Valid staging token → 200 (or 200 with data)
//
// Usage:
//   PERF_RUST_BASE_URL=<staging-url> node scripts/staging-verify-auth.js
// Reads .staging-token (generated by staging-jwt.js) for the valid token check.

const fs   = require('fs');
const path = require('path');

const BASE_URL = process.env.PERF_RUST_BASE_URL;
if (!BASE_URL) {
  console.error('[staging-verify-auth] ERROR: PERF_RUST_BASE_URL not set.');
  process.exit(1);
}

const TOKEN_PATH = path.join(__dirname, '..', '.staging-token');
let validToken;
try {
  validToken = fs.readFileSync(TOKEN_PATH, 'utf8').trim();
} catch {
  console.error('[staging-verify-auth] .staging-token not found. Run: node scripts/staging-jwt.js');
  process.exit(1);
}

// Use an auth-required endpoint for the checks
const ENDPOINT = `${BASE_URL}/api/v2/cortex/evaluate-policy`;
const BODY = JSON.stringify({
  action_type: 'SEND_POLITE_REMINDER',
  amount: 1000,
  risk_level: 'low',
  customer_id: '11111111-1111-1111-1111-111111111111',
});

async function check(label, headers) {
  const res = await fetch(ENDPOINT, {
    method: 'POST',
    headers: { 'content-type': 'application/json', ...headers },
    body: BODY,
  });
  return { label, status: res.status };
}

async function run() {
  console.log(`[staging-verify-auth] Testing auth enforcement on ${BASE_URL}`);

  const results = await Promise.all([
    check('missing token', {}),
    check('invalid token', { authorization: 'Bearer invalidtoken123' }),
    check('valid staging token', { authorization: `Bearer ${validToken}` }),
  ]);

  let allOk = true;
  for (const r of results) {
    const expected = r.label === 'valid staging token' ? 200 : 401;
    const pass = r.status === expected;
    if (!pass) allOk = false;
    console.log(`  [${pass ? 'PASS' : 'FAIL'}] ${r.label}: HTTP ${r.status} (expected ${expected})`);
  }

  if (!allOk) {
    console.error('\n[staging-verify-auth] Auth verification FAILED. Do not proceed with perf test.');
    process.exit(1);
  }
  console.log('\n[staging-verify-auth] Auth: OK — missing/invalid rejected, valid accepted.');
}

run().catch(err => { console.error('[staging-verify-auth] Fatal:', err.message); process.exit(1); });
